&lt;p data-start=&quot;568&quot; data-end=&quot;589&quot;&gt;&lt;strong data-start=&quot;568&quot; data-end=&quot;587&quot;&gt;Deine Aufgaben:&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li data-start=&quot;592&quot; data-end=&quot;673&quot;&gt;Identifizierung und aktive Gewinnung neuer Geschäftsmöglichkeiten im DACH-Markt&lt;/li&gt;
&lt;li data-start=&quot;676&quot; data-end=&quot;753&quot;&gt;Proaktive Erschließung ungenutzter Marktsegmente und potenzieller Neukunden&lt;/li&gt;
&lt;li data-start=&quot;756&quot; data-end=&quot;835&quot;&gt;Aufbau und Pflege einer starken Pipeline mit qualifizierten Leads und Chancen&lt;/li&gt;
&lt;li data-start=&quot;838&quot; data-end=&quot;927&quot;&gt;Analyse der Bedürfnisse potenzieller Kunden und Präsentation maßgeschneiderter Lösungen&lt;/li&gt;
&lt;li data-start=&quot;930&quot; data-end=&quot;1010&quot;&gt;Erfolgreiche Vertragsverhandlungen führen und neue Partnerschaften abschließen&lt;/li&gt;
&lt;li data-start=&quot;1013&quot; data-end=&quot;1095&quot;&gt;Ausbau deines Netzwerks durch Cold Calling, E-Mails, LinkedIn und weitere Kanäle&lt;/li&gt;
&lt;li data-start=&quot;1098&quot; data-end=&quot;1187&quot;&gt;Monatliche Vertriebsziele übertreffen und maßgeblich zum Unternehmenswachstum beitragen&lt;/li&gt;
&lt;/ul&gt;
&lt;p data-start=&quot;1189&quot; data-end=&quot;1207&quot;&gt;&lt;strong data-start=&quot;1189&quot; data-end=&quot;1205&quot;&gt;Dein Profil:&lt;/strong&gt;&lt;/p&gt;
